+func TestTruncate(t *testing.T) {
+	tests := []struct {
+		name   string
+		input  string
+		maxLen int
+		want   string
+	}{
+		{"short string", "hello", 10, "hello"},
+		{"exact length", "hello", 5, "hello"},
+		{"needs truncation", "hello world", 8, "hello..."},
+		{"maxLen 3", "hello", 3, "hel"},
+		{"maxLen 2", "hello", 2, "he"},
+		{"maxLen 1", "hello", 1, "h"},
+		{"maxLen 0", "hello", 0, ""},
+		{"maxLen negative", "hello", -1, ""},
+		{"empty string", "", 5, ""},
+	}
+
+	for _, tt := range tests {
+		t.Run(tt.name, func(t *testing.T) {
+			got := truncate(tt.input, tt.maxLen)
+			if got != tt.want {
+				t.Errorf("truncate(%q, %d) = %q, want %q", tt.input, tt.maxLen, got, tt.want)
+			}
+		})
+	}
+}

@@ -163,9 +163,16 @@ func (h *Handoff) ValidateAndSetDefaults() ValidationErrors {

 // truncate shortens a string for logging purposes.
 func truncate(s string, maxLen int) string {
+	if maxLen <= 0 {
+		return ""
+	}
 	if len(s) <= maxLen {
 		return s
 	}
+	// Need at least 4 chars to fit content + "..." (1 char + 3 for ellipsis)
+	if maxLen <= 3 {
+		return s[:maxLen]
+	}
 	return s[:maxLen-3] + "..."
 }
